import { axis } from '../core/main-zc-init';
import { d3_select } from '../core/d3-constants';
import { PolarAxisParser } from './parser/polaraxis-parser';

axis.polar = function () {
    var scaleObj, chartObj, radius, columnIndices, tickFormat, tickValues, axisType, newAxisParser;

    function axis_polar(g) {
        g.each(function (data) {
            var g = d3_select(this);
            var subtickmark = data.subtickmark || {},
                subticksCount = +subtickmark.count || 0;

            var ticks = tickValues || (scaleObj.ticks ? scaleObj.ticks() : scaleObj.domain()),
                subticks = d3_svg_axisSubdivide(scaleObj, ticks, subticksCount),
                range = scaleObj.range();

            let dependencies = {
                type: 'polar',
                chart: chartObj,
                container: g,
                renderer: axis_polar,
                data, ticks, subticks, range
            };

            newAxisParser = new PolarAxisParser(dependencies);
            newAxisParser.render();
        });
    }

    axis_polar.scale = function (_) {
        return arguments.length ? (scaleObj = _, axis_polar) : scaleObj;
    };
    axis_polar.chartObj = function (_) {
        return arguments.length ? (chartObj = _, axis_polar) : chartObj;
    };
    axis_polar.radius = function (_) {
        return arguments.length ? (radius = _, axis_polar) : radius;
    };
    axis_polar.columnIndices = function (_) {
        return arguments.length ? (columnIndices = _, axis_polar) : columnIndices;
    };
    axis_polar.tickValues = function (_) {
        return arguments.length ? (tickValues = _, axis_polar) : tickValues;
    };
    axis_polar.tickFormat = function (_) {
        return arguments.length ? (tickFormat = _, axis_polar) : tickFormat;
    };
    axis_polar.type = function (_) {
        return arguments.length ? (axisType = _, axis_polar) : axisType;
    }
    axis_polar.parser = function (_) {
        return arguments.length ? (newAxisParser = _, axis_polar) : newAxisParser;
    }

    return axis_polar;
};

function d3_svg_axisSubdivide(scaleObj, ticks, m) {
    subticks = [];
    if (m && ticks.length > 1) {
        var extent = d3_scaleExtent(scaleObj.domain()),
            subticks,
            i = -1,
            n = ticks.length,
            d = (ticks[1] - ticks[0]) / ++m,
            j,
            v;
        while (++i < n) {
            for (j = m; --j > 0;) {
                if ((v = +ticks[i] - j * d) >= extent[0]) {
                    subticks.push(v);
                }
            }
        }
        for (--i, j = 0; ++j < m && (v = +ticks[i] + j * d) < extent[1];) {
            subticks.push(v);
        }
    }
    return subticks;
}

function d3_scaleExtent(domain) {
    var start = domain[0],
        stop = domain[domain.length - 1];
    return start < stop ? [start, stop] : [stop, start];
}